const sysmacStudioInstance = new ec2.Instance(this, 'SysmacStudioInstance', {
  vpc: vpc,
  instanceType: ec2.InstanceType.T3_MEDIUM,
  machineImage: ec2.MachineImage.fromLookup({ // Use a hardened AMI
    owners: ['amazon'],
    name: 'Amazon Linux 2'
  }),
  securityGroup: new ec2.SecurityGroup(this, 'SysmacStudioSG', {
    allowAllOutbound: false, // Restrict outbound traffic
    // Only allow SSH from a specific bastion host
