       fis = new FileInputStream("my_file.txt");
       // Process file
   } catch (IOException e) {
       // Handle exception
   } finally {
       if (fis != null) {
           try {
               fis.close();
           } catch (IOException e) {
               // Log the error securely
           }
       }
   }
