    core,
    aws_iam as iam,
    aws_lambda as lambda_
)

class MyStack(core.Stack):

    def __init__(self, scope: core.Construct, construct_id: str, **kwargs) -> None:
        super().__init__(scope, construct_id, **kwargs)

        # Define a Lambda function (potentially vulnerable)
        my_lambda = lambda_.Function(
            self, "MyLambda",
            runtime=lambda_.Runtime.PYTHON_3_9,
            handler="index.handler",
            code=lambda_.Code.from_asset("lambda_function")
        )

        # Create an IAM role with only the necessary permissions
        execution_role = iam.Role(
            self, "MyLambdaExecutionRole",
            assumed_by=iam.ServicePrincipal("lambda.amazonaws.com"),
            managed_policies=[
                iam.ManagedPolicy.from_aws_managed_policy_name("AWSLambdaBasicExecutionRole") # Minimal permissions
            ]
        )

        my_lambda.role = execution_role
```

