      vpc: new ec2.Vpc(this, 'GitLabRunnerVPC', {
        maxAzs: 2,
      }),
    });

    // Define the ECS task definition
    const taskDefinition = new ecs.FargateTaskDefinition(this, 'GitLabRunnerTaskDef', {
      cpu: 256,
      memoryLimitMiB: 512,
    });

    // Add the GitLab Runner container to the task definition
    const runnerContainer = taskDefinition.addContainer('GitLabRunnerContainer', {
      image: ecs.ContainerImage.fromEcrRepository(runnerRepo, 'latest'), // Use latest tag after updating the image
