        GITLAB_RUNNER_URL: 'YOUR_GITLAB_INSTANCE_URL',
      },
    });

    // Create an ECS service
    const service = new ecs.FargateService(this, 'GitLabRunnerService', {
      cluster: cluster,
      taskDefinition: taskDefinition,
      desiredCount: 1,
    });

